/*!
 * Mombie splash – custom nav/scroll JS (Bootstrap 5 compatible)
 */
(function ($) {
  "use strict";

  // Smooth scroll for anchor nav links
  $('a.js-scroll-trigger[href*="#"]:not([href="#"])').on('click', function () {
    if (location.pathname.replace(/^\//, '') === this.pathname.replace(/^\//, '') &&
        location.hostname === this.hostname) {
      var target = $(this.hash);
      target = target.length ? target : $('[name=' + this.hash.slice(1) + ']');
      if (target.length) {
        $('html, body').animate({ scrollTop: target.offset().top - 48 }, 1000, 'easeInOutExpo');
        return false;
      }
    }
  });

  // Collapse navbar when a scroll-trigger link is clicked (Bootstrap 5 API)
  $('.js-scroll-trigger').on('click', function () {
    var navbarEl = document.getElementById('navbarResponsive');
    var bsCollapse = bootstrap.Collapse.getInstance(navbarEl);
    if (bsCollapse) { bsCollapse.hide(); }
  });

  // Shrink navbar on scroll
  function navbarShrink() {
    if ($('#mainNav').offset().top > 100) {
      $('#mainNav').addClass('navbar-shrink');
    } else {
      $('#mainNav').removeClass('navbar-shrink');
    }
  }
  navbarShrink();
  $(window).on('scroll', navbarShrink);

})(jQuery);
